        | t0: byte3=tileDeco[t0]&FF, byte32=tileDeco[t0]>>8
        move.w  d0,d1
    3f76:	|   move.w d0,d1
        add.w   d4,d1
    3f78:	|   add.w d4,d1
        andi.w  #63,d1
    3f7a:	|   andi.w #63,d1
        add.w   d1,d1
    3f7e:	|   add.w d1,d1
        move.w  (a3,d1.w),d2           | d2 = tileDeco[t0]
    3f80:	|   move.w (0,a3,d1.w),d2
        move.b  d2,3(a1)              | byte3 = low byte
    3f84:	|   move.b d2,3(a1)
        lsr.w   #8,d2
    3f88:	|   lsr.w #8,d2
        move.b  d2,32(a1)             | byte32 = high byte
    3f8a:	|   move.b d2,32(a1)

        | Clear words 2..15 (bytes 4..31)
        clr.l   4(a1)
    3f8e:	|   clr.l 4(a1)
        clr.l   8(a1)
    3f92:	|   clr.l 8(a1)
        clr.l   12(a1)
    3f96:	|   clr.l 12(a1)
        clr.l   16(a1)
    3f9a:	|   clr.l 16(a1)
        clr.l   20(a1)
    3f9e:	|   clr.l 20(a1)
        clr.l   24(a1)
    3fa2:	|   clr.l 24(a1)
        clr.l   28(a1)
    3fa6:	|   clr.l 28(a1)
        | Clear bytes 36-39
        clr.l   36(a1)
    3faa:	|   clr.l 36(a1)

        lea     40(a1),a1              | next row
    3fae:	|   lea 40(a1),a1
        addq.w  #1,d0
    3fb2:	|   addq.w #1,d0
        dbra    d3,.cp0_row
    3fb4:	'-- dbf d3,3f30 <.cp0_row>

| ---- PLANE 1: all zeros ----
        | a1 is already at plane0 + 10240 = plane1 base
        move.w  #255,d3
    3fb8:	    move.w #255,d3

00003fbc <.cp1_row>:
.cp1_row:
        clr.l   (a1)
    3fbc:	,-> clr.l (a1)
        clr.l   4(a1)
    3fbe:	|   clr.l 4(a1)
        clr.l   8(a1)
    3fc2:	|   clr.l 8(a1)
        clr.l   12(a1)
    3fc6:	|   clr.l 12(a1)
        clr.l   16(a1)
    3fca:	|   clr.l 16(a1)
        clr.l   20(a1)
    3fce:	|   clr.l 20(a1)
        clr.l   24(a1)
    3fd2:	|   clr.l 24(a1)
        clr.l   28(a1)
    3fd6:	|   clr.l 28(a1)
        clr.l   32(a1)
    3fda:	|   clr.l 32(a1)
        clr.l   36(a1)
    3fde:	|   clr.l 36(a1)
        lea     40(a1),a1
    3fe2:	|   lea 40(a1),a1
        dbra    d3,.cp1_row
    3fe6:	'-- dbf d3,3fbc <.cp1_row>

| ---- PLANES 2, 3, 4: walls=FF, middle=0 ----
        | a1 is now at plane2 base
        moveq   #2,d3                   | 3 planes
    3fea:	    moveq #2,d3

00003fec <.cp_hi_plane>:
.cp_hi_plane:
        move.w  #255,d2                 | 256 rows
    3fec:	move.w #255,d2

00003ff0 <.cp_hi_row>:
.cp_hi_row:
        move.l  #0xFFFFFFFF,(a1)       | bytes 0-3 = FF
    3ff0:	,-> move.l #-1,(a1)
        clr.l   4(a1)
    3ff6:	|   clr.l 4(a1)
        clr.l   8(a1)
    3ffa:	|   clr.l 8(a1)
        clr.l   12(a1)
    3ffe:	|   clr.l 12(a1)
        clr.l   16(a1)
    4002:	|   clr.l 16(a1)
        clr.l   20(a1)
    4006:	|   clr.l 20(a1)
        clr.l   24(a1)
    400a:	|   clr.l 24(a1)
        clr.l   28(a1)
    400e:	|   clr.l 28(a1)
        move.l  #0xFFFFFFFF,32(a1)     | bytes 32-35 = FF
    4012:	|   move.l #-1,32(a1)
        clr.l   36(a1)
    401a:	|   clr.l 36(a1)
        lea     40(a1),a1
    401e:	|   lea 40(a1),a1
        dbra    d2,.cp_hi_row
    4022:	'-- dbf d2,3ff0 <.cp_hi_row>
        dbra    d3,.cp_hi_plane
    4026:	    dbf d3,3fec <.cp_hi_plane>

        movem.l (sp)+,d0-d7/a0-a6
    402a:	    movem.l (sp)+,d0-a6
        rts
    402e:	    rts
